export abstract class HttpClient implements HttpClientInterface {
  readonly MAX_RETRY_ATTEMPTS = 3;
  readonly BACKOFF_MULTIPLIER = 1.5;
  readonly MINIMUM_SLEEP_TIME_IN_MILLISECONDS = 500;
